async function addAsync(a, b) {
  return a + b;
}

async function getLengthAsync(text) {
  const value = await Promise.resolve(text);
  return value.length;
}

async function getPositiveAsync(nums) {
  return nums.filter((n) => n > 0);
}

async function sumAsync(nums) {
  const values = await Promise.resolve(nums);
  return values.reduce((total, n) => total + n, 0);
}
